        return render(request, 'error.html', {'error': "Invalid record ID"})

    patient_data = Patient.objects.filter(id=record_id).values('id', 'name', 'age', 'condition')

    if not patient_data:
        return render(request, 'error.html', {'error': "Record not found"})

    return render(request, 'medical_record.html', {'patient_data': dict(patient_data[0])})

